May want to have different levels of output for different loglevels. 
```
func (b *Executor) UnrecognizedInstruction(step *imagebuilder.Step) error {
        if b.ignoreUnrecognizedInstructions {
                logrus.Debugf("+(UNIMPLEMENTED?) %#v", step)
                return nil
        }
        if logrus.GetLevel() == logrus.ErrorLevel {
// no DebugF
                return errors.Errorf("Unknown instruction: %v", step.Command)
        } else if logrus.GetLevel() == logrus.DebugLevel {
// add DebugF
                logrus.Debugf("Unknown instruction: %#v", step)
                return errors.Errorf("Unknown instruction: %#v", step)
        } else {
// what else should it check?
                return errors.Errorf("Unknown instruction: %#v", step)
        }

}
